                {"speaker": "Child", "swissGerman": "De mit de Raketene! Nei, wart — de mit de Dino!", "german": "Den mit den Raketen! Nein, warte — den mit den Dinos!", "english": "The one with the rockets! No, wait — the one with the dinos!", "spanish": "¡El de los cohetes! No, espera, ¡el de los dinosaurios!"},
                {"speaker": "You", "swissGerman": "Entscheid dich! Eins, zwöi, drü — de Dino-Pyjama isch gnoh.", "german": "Entscheide dich! Eins, zwei, drei — der Dino-Schlafanzug ist genommen.", "english": "Make up your mind! One, two, three — the dino pajamas it is.", "spanish": "¡Decídete! Uno, dos, tres — el pijama de dinosaurio."},
                {"speaker": "Child", "swissGerman": "Chasch du mir hälfe? Ich chum nöd i d'Ärmel ine.", "german": "Kannst du mir helfen? Ich komme nicht in die Ärmel rein.", "english": "Can you help me? I can't get into the sleeves.", "spanish": "¿Puedes ayudarme? No puedo meterme en las mangas."},
                {"speaker": "You", "swissGerman": "Do, de rächt Arm zerscht... und jetzt de lingg.", "german": "Hier, der rechte Arm zuerst... und jetzt der linke.", "english": "Here, right arm first... and now the left.", "spanish": "Aquí, primero el brazo derecho... y ahora el izquierdo."},
                {"speaker": "Child", "swissGerman": "Danke! Jetzt bin ich en Dino! Raawr!", "german": "Danke! Jetzt bin ich ein Dino! Raawr!", "english": "Thanks! Now I'm a dino! Raawr!", "spanish": "¡Gracias! ¡Ahora soy un dino! ¡Raawr!"},
